#include <iostream>
#include <string>
#include <memory>
#include <vector>

using namespace std;

class Document {
public:
    virtual void display() = 0;
    virtual ~Document() {}
};

class RealDocument : public Document {
private:
    string content;

public:
    RealDocument(const string& content) : content(content) {
        cout << "Loading sensitive document..." << endl;
    }

    void display() override {
        cout << "Document content: " << content << endl;
    }
};

class SecureDocumentProxy : public Document {
private:
    shared_ptr<RealDocument> realDocument;
    string content;
    vector<string> allowedRoles;

    bool hasAccess(const string& role) {
        for (const auto& allowed : allowedRoles) {
            if (allowed == role) {
                return true;
            }
        }
        return false;
    }

public:
    SecureDocumentProxy(const string& content, const vector<string>& roles)
        : content(content), allowedRoles(roles) {}

    void display() override {
        cout << "Access control check..." << endl;

        string userRole;
        cout << "Enter your role (admin/manager/user): ";
        cin >> userRole;

        if (!hasAccess(userRole)) {
            cout << "Access denied! Insufficient permissions." << endl;
            return;
        }

        if (!realDocument) {
            realDocument = make_shared<RealDocument>(content);
        }

        realDocument->display();
    }
};

int main() {
    cout << "=== Proxy Pattern Demo ===" << endl << endl;

    vector<string> adminOnly = {"admin"};
    vector<string> adminAndManager = {"admin", "manager"};

    shared_ptr<Document> doc1 = make_shared<SecureDocumentProxy>(
        "Top Secret Financial Report", adminOnly);

    shared_ptr<Document> doc2 = make_shared<SecureDocumentProxy>(
        "Project Roadmap 2026", adminAndManager);

    cout << "--- Accessing Document 1 (Admin Only) ---" << endl;
    doc1->display();
    cout << endl;

    cout << "--- Accessing Document 2 (Admin & Manager) ---" << endl;
    doc2->display();
    cout << endl;

    cout << "--- Accessing Document 2 again (cached) ---" << endl;
    doc2->display();

    return 0;
}

