#include <iostream>
#include <string>

using namespace std;

class Document {
public:
    virtual void display() = 0;
    virtual ~Document() {}
};

class RealDocument : public Document {
private:
    string content;
public:
    RealDocument(const string& c) : content(c) {}
    void display() override { cout << content << endl; }
};

class SecureDocumentProxy : public Document {
private:
    RealDocument* doc = nullptr;
    string content;
    string allowedRole;
public:
    SecureDocumentProxy(const string& c, const string& role) 
        : content(c), allowedRole(role) {}

    void display() override {
        string role;
        cout << "Enter role (admin/manager/user): ";
        cin >> role;

        if (role != allowedRole && role != "admin") {
            cout << "Access denied!" << endl;
            return;
        }

        if (!doc) doc = new RealDocument(content);
        doc->display();
    }
    ~SecureDocumentProxy() { delete doc; }
};

int main() {
    Document* doc1 = new SecureDocumentProxy("Top Secret", "admin");
    Document* doc2 = new SecureDocumentProxy("Project Plan", "manager");

    cout << "--- Doc 1 ---" << endl;
    doc1->display();

    cout << "--- Doc 2 ---" << endl;
    doc2->display();

    delete doc1;
    delete doc2;
    return 0;
}

